import datetime

def is_valid_time(time_str):
    try:
        return time_str.split()[0] in ["12", "1", "2"]
    except (IndexError, ValueError):
        return False

def get_current_date():
    now = datetime.datetime.now()
    return now.strftime("%Y-%m-%d")

current_date = get_current_date()

print("IYI Dining Current Date:", current_date)

timings = {
    "12:00 PM": "Lunch",
    "1:00 PM": "Afternoon Tea",
    "2:00 PM": "Aperitif",
    "3:00 PM": "Dinner"
}

for time, description in timings.items():
    if is_valid_time(time):
        print(f"{time}: {description}")

